     1	import { useState } from 'react';
     2	import { Link, useNavigate, useParams } from 'react-router-dom';
     3	import { useModelShow, useModelUpdate, useModelDelete } from '@rhino-dev/rhino-react';
     4	import type { Blog } from '../types';
     5	import { Icon } from '../components/Icons';
     6	import { useToast } from '../components/Toaster';
     7	import { fmtDate, fmtRelative } from '../lib/format';
     8	import { Loading } from './DashboardPage';
     9	
    10	export function BlogDetailPage() {
    11	  const { id } = useParams<{ id: string }>();
    12	  const nav = useNavigate();
    13	  const toast = useToast();
    14	  const blog = useModelShow<Blog>('blogs', id);
    15	  const update = useModelUpdate<Blog>('blogs');
    16	  const del = useModelDelete<Blog>('blogs');
    17	
    18	  const [editing, setEditing] = useState(false);
    19	
    20	  if (blog.isLoading) return <Loading />;
    21	  const b = blog.data;
    22	  if (blog.error || !b) return <div className="empty"><h3>Not found</h3><p>This blog may have been deleted.</p></div>;
    23	
    24	  return (
    25	    <>
    26	      <div className="page-head">
    27	        <div>
    28	          <div className="row" style={{ marginBottom: 4 }}>
    29	            <Link to="/blogs" className="btn btn-ghost btn-sm"><Icon.arrowL size={12} /> Back</Link>
    30	            <span className={`pill ${b.published ? 'pill-active' : 'pill-draft'}`}>
    31	              {b.published ? 'Published' : 'Draft'}
    32	            </span>
    33	          </div>
    34	          <h1 className="page-title">{b.title || 'Untitled'}</h1>
    35	        </div>
    36	        <div className="row">
    37	          <button className="btn" onClick={() => setEditing(true)}><Icon.edit size={14} /> Edit</button>
    38	          <button
    39	            className="btn btn-danger"
    40	            onClick={async () => {
    41	              if (!confirm(`Delete blog "${b.title || 'Untitled'}"?`)) return;
    42	              await del.mutateAsync(b.id);
    43	              toast('Blog moved to trash', 'ok');
    44	              nav('/blogs');
    45	            }}
    46	          ><Icon.trash size={14} /> Delete</button>
    47	        </div>
    48	      </div>
    49	
    50	      <div className="detail-grid">
    51	        <div>
    52	          <div className="card" style={{ padding: 24 }}>
    53	            <div style={{ whiteSpace: 'pre-wrap', fontSize: 15, lineHeight: 1.6 }}>
    54	              {b.body || <span className="faint">No content</span>}
    55	            </div>
    56	          </div>
    57	        </div>
    58	
    59	        <aside>
    60	          <div className="card">
    61	            <div className="card-header"><div className="card-title">Blog details</div></div>
    62	            <div className="card-body">
    63	              <dl className="kv">
    64	                <dt>ID</dt><dd className="mono">{b.id}</dd>
    65	                <dt>Org</dt><dd className="mono">#{b.organization_id}</dd>
    66	                <dt>Status</dt>
    67	                <dd>
    68	                  <span className={`pill ${b.published ? 'pill-active' : 'pill-draft'}`}>
    69	                    {b.published ? 'Published' : 'Draft'}
    70	                  </span>
    71	                </dd>
    72	                <dt>Created</dt><dd className="muted">{fmtDate(b.created_at)}</dd>
    73	                <dt>Updated</dt><dd className="muted">{fmtRelative(b.updated_at)}</dd>
    74	              </dl>
    75	            </div>
    76	          </div>
    77	        </aside>
    78	      </div>
    79	
    80	      {editing && (
    81	        <EditBlogModal
    82	          blog={b}
    83	          busy={update.isPending}
    84	          onClose={() => setEditing(false)}
    85	          onSave={async data => {
    86	            try {
    87	              await update.mutateAsync({ id: b.id, data });
    88	              toast('Blog updated', 'ok');
    89	              setEditing(false);
    90	            } catch (err) {
    91	              toast(`Update failed: ${(err as Error).message}`, 'error');
    92	            }
    93	          }}
    94	        />
    95	      )}
    96	    </>
    97	  );
    98	}
    99	
   100	function EditBlogModal({ blog, onClose, onSave, busy }: { blog: Blog; onClose: () => void; onSave: (data: Partial<Blog>) => Promise<void>; busy: boolean }) {
   101	  const [title, setTitle] = useState(blog.title || '');
   102	  const [body, setBody] = useState(blog.body || '');
   103	  const [published, setPublished] = useState(blog.published || false);
   104	
   105	  return (
   106	    <div className="modal-backdrop" onClick={onClose}>
   107	      <div className="modal" onClick={e => e.stopPropagation()}>
   108	        <div className="modal-head">
   109	          <div className="modal-title">Edit blog</div>
   110	          <button className="btn btn-ghost btn-icon" onClick={onClose}><Icon.close /></button>
   111	        </div>
   112	        <div className="modal-body">
   113	          <form className="form" onSubmit={e => { e.preventDefault(); onSave({ title, body, published }); }}>
   114	            <div className="field">
   115	              <label>Title</label>
   116	              <input className="input" value={title} onChange={e => setTitle(e.target.value)} required />
   117	            </div>
   118	            <div className="field">
   119	              <label>Body</label>
   120	              <textarea className="input" rows={8} value={body} onChange={e => setBody(e.target.value)} required />
   121	            </div>
   122	            <div className="field-row" style={{ display: 'flex', alignItems: 'center', gap: 8, margin: '12px 0' }}>
   123	              <input
   124	                type="checkbox"
   125	                id="published"
   126	                checked={published}
   127	                onChange={e => setPublished(e.target.checked)}
   128	              />
   129	              <label htmlFor="published" style={{ margin: 0, cursor: 'pointer' }}>Published</label>
   130	            </div>
   131	            <div className="modal-foot" style={{ padding: 0, border: 0 }}>
   132	              <button type="button" className="btn btn-ghost" onClick={onClose}>Cancel</button>
   133	              <button type="submit" className="btn btn-primary" disabled={busy}>
   134	                {busy ? <span className="spinner" /> : <Icon.check size={14} />} Save
   135	              </button>
   136	            </div>
   137	          </form>
   138	        </div>
   139	      </div>
   140	    </div>
   141	  );
   142	}
